title = #{title}, full_name = #{fullName}, email = #{email}, phone = #{phone}, location = #{location}, linkedin_url = #{linkedinUrl}, github_url = #{githubUrl}, personal_website = #{personalWebsite}, avatar_url = #{avatarUrl}, professional_summary = #{professionalSummary}, template_id = #{templateId}, updated_at = NOW()
